
.panel {
  width: 100%;
  max-width: 480px;
  font-family: monospace;
  font-size: 13px;
  margin: 0 auto;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6px 10px;
  background: #1a1a1a;
  border-radius: 8px 8px 0 0;
  color: #ccc;
  border-bottom: 1px solid #333;
}

.time {
  color: #8ec8f0;
  font-weight: 600;
}

.location {
  color: #aaa;
}

.actions {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 8px 10px;
  background: #1e1e1e;
  border-radius: 0 0 8px 8px;
}

.action-btn {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 12px;
  background: #2a2a2a;
  border: 1px solid #3a3a3a;
  border-radius: 6px;
  color: #ddd;
  cursor: pointer;
  font-family: monospace;
  font-size: 13px;
  transition: background 0.15s;

  &:hover:not(:disabled) {
    background: #3a3a3a;
    border-color: #5a5a5a;
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

.act-label {
  text-align: left;
}

.act-time {
  color: #888;
  font-size: 11px;
}

.loading {
  text-align: center;
  padding: 8px;
  color: #888;
}
